INSERT INTO `skp_perilaku_awal_tahun_pegawai` (`ID_SKP`, `NAMA`, `NIP`, `NAMA_ATASAN_LANGSUNG`, `NIP_ATASAN_LANGSUNG`, `PERILAKU_KERJA_BERORIENTASI_PELAYANAN`, `PERILAKU_KERJA_AKUNTABEL`, `PERILAKU_KERJA_KOMPETEN`, `PERILAKU_KERJA_HARMONIS`, `PERILAKU_KERJA_LOYAL`, `PERILAKU_KERJA_ADAPTIF`, `PERILAKU_KERJA_KOLABORATIF`, `EKSPEKTASI_PIMPINAN_BERORIENTASI_PELAYANAN`, `EKSPEKTASI_PIMPINAN_AKUNTABEL`, `EKSPEKTASI_PIMPINAN_KOMPETEN`, `EKSPEKTASI_PIMPINAN_HARMONIS`, `EKSPEKTASI_PIMPINAN_LOYAL`, `EKSPEKTASI_PIMPINAN_ADAPTIF`, `EKSPEKTASI_PIMPINAN_KOLABORATIF`, `UMPAN_BALIK_BERORIENTASI_PELAYANAN`, `UMPAN_BALIK_AKUNTABEL`, `UMPAN_BALIK_KOMPETEN`, `UMPAN_BALIK_HARMONIS`, `UMPAN_BALIK_LOYAL`, `UMPAN_BALIK_ADAPTIF`, `UMPAN_BALIK_KOLABORATIF`, `TRIWULAN`, `TAHUN`, `STATUS`, `TANGGAL_INPUT_SKP`, `ID_SKP_GLOBAL`, `PANGKAT_GOL_RUANG`, `JABATAN`, `UNIT_KERJA`, `SATUAN_KERJA`) VALUES
(2, 'A. Riri Asturi Tenri Banna, S.E., M.M.', '198710312010122003', 'Meydi Zulqadri, S.H.,M.H', '198705132010121006', '- Memahami dan memenuhi kebutuhan masyarakat.\n- Ramah, cekatan, solutif, dan dapat diandalkan.\n- Melakukan perbaikan tiada henti.', '- Melaksanakan tugas dengan jujur, bertanggungjawab, cermat, disiplin dan berintegritas tinggi.\n- Menggunakan kekayaan dan barang milik negara secara bertanggungjawab, efektif dan efisien.\n- Tidak menyalahgunakan kewenangan jabatan.', '- Meningkatkan kompetensi diri untuk menjawab tantangan yang selalu berubah.\n- Membantu orang lain belajar.\n- Melaksanakan tugas dengan kualitas terbaik.', '- Menghargai setiap orang apapun latar belakangnya.\n- Suka menolong orang lain.\n- Membangun lingkungan kerja yang kondusif.', '- Memegang teguh ideologi Pancasila, Undang-Undang Dasar Negara Republik Indonesia Tahun 1945, setia pada Negara Kesatuan Republik Indonesia serta pemerintahan yang sah.\n- Menjaga nama baik ASN, Pimpinan, Instansi dan Negara.\n- Menjaga rahasia jabatan dan negara.', '- Cepat menyesuaikan diri menghadapi perubahan\n- Terus berinovasi dan mengembangkan kreativitas\n- Bertindak proaktif', '- Memberi kesempatan kepada berbagai pihak untuk berkontribusi.\n- Terbuka dalam bekerjasama untuk menghasilkan nilai tambah.\n- Menggerakan pemanfaatan berbagai sumber daya untuk tujuan bersama.', 'Ekspektasi Khusus Pimpinan : Memberikan layanan yang responsif, solutif dan\r\nramah dalam memberikan layanan internal', 'Ekspektasi Khusus Pimpinan : Melaksanakan tugas dengan jujur, bertanggung\r\njawab, cermat dan disiplin serta menjunjung tinggi tata nilai BerAKHLAK dan \r\nPASTI', 'Ekspektasi Khusus Pimpinan : Menyelesaikan  setiap  pekerjaan  sesuai  dengan  \r\ntarget  dan standar kualitas yang ditetapkan serta mampu meningkatkan\r\nkompetensi diri sesuai dengan tuntutan perubahan', 'Ekspektasi Khusus Pimpinan : Saling menghargai dengan pegawai lain untuk\r\nmembangun lingkungan kerja yang nyaman dan kondusif', 'Ekspektasi Khusus Pimpinan : Utamakan tugas dan fungsi sebagai ASN diatas\r\nkepentingan pribadi/golongan', 'Ekspektasi Khusus Pimpinan : Mampu menyesuaikan diri dalam menghadapi \r\nsetiap perubahan dalam organisasi', 'Ekspektasi Khusus Pimpinan : Membangun kerjasama dan kolaborasi yang baik \r\ndengan rekan kerja dan stakeholder untuk kelancaran pelaksanaan tugas dan\r\nfungsi', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1, 2026, 'draft', '2026-04-27 17:07:12', 6, 'Penata Tk. I / IIId', 'Penata Kelola Pemerintahan', 'Bagian TU dan UMUM', 'Bagian TU dan UMUM'),
(3, 'Meydi Zulqadri, S.H.,M.H', '198705132010121006', 'Andi Basmal, S.Sos., S.H, M.H', '197202151992031002', '- Memahami dan memenuhi kebutuhan masyarakat.\n- Ramah, cekatan, solutif, dan dapat diandalkan.\n- Melakukan perbaikan tiada henti.', '- Melaksanakan tugas dengan jujur, bertanggungjawab, cermat, disiplin dan berintegritas tinggi.\n- Menggunakan kekayaan dan barang milik negara secara bertanggungjawab, efektif dan efisien.\n- Tidak menyalahgunakan kewenangan jabatan.', '- Meningkatkan kompetensi diri untuk menjawab tantangan yang selalu berubah.\n- Membantu orang lain belajar.\n- Melaksanakan tugas dengan kualitas terbaik.', '- Menghargai setiap orang apapun latar belakangnya.\n- Suka menolong orang lain.\n- Membangun lingkungan kerja yang kondusif.', '- Memegang teguh ideologi Pancasila, Undang-Undang Dasar Negara Republik Indonesia Tahun 1945, setia pada Negara Kesatuan Republik Indonesia serta pemerintahan yang sah.\n- Menjaga nama baik ASN, Pimpinan, Instansi dan Negara.\n- Menjaga rahasia jabatan dan negara.', '- Cepat menyesuaikan diri menghadapi perubahan\n- Terus berinovasi dan mengembangkan kreativitas\n- Bertindak proaktif', '- Memberi kesempatan kepada berbagai pihak untuk berkontribusi.\n- Terbuka dalam bekerjasama untuk menghasilkan nilai tambah.\n- Menggerakan pemanfaatan berbagai sumber daya untuk tujuan bersama.', 'Ekspektasi Khusus Pimpinan :  Memberikan layanan yang esponsif, solutif dan ramah dalam memberikan layanan internal', 'Ekspektasi Khusus Pimpinan :  Melaksanakan tugas dengan jujur, bertanggung jawab, cermat, dan disiplin serta menjunjung tinggi tata Nilai PASTI', 'Ekspektasi Khusus Pimpinan : Menyelesaikan setiap pekerjaan sesuai dengan target dan mampu meningkatkan kompetensi diri sesuai dengan tuntutan perubahan', 'Ekspektasi Khusus Pimpinan : Saling menghargai dengan pegawai lain untuk membangun lingkungan kerja yang nyaman dan kondusif', 'Ekspektasi Khusus Pimpinan : Mengutamakan kepentingan negara diatas kepentingan pribadi dan/ atau golongan serta senantiasa menjaga nama baik ASN dan Institusi', 'Ekspektasi Khusus Pimpinan : Melakukan inovasi serta mampu menyesuaikan diri dalam menghadapi setiap perubahan', 'Ekspektasi Khusus Pimpinan : Membangun kerjasama dan kolaborasi yang baik dengan pimpinan, teman kerja dan stakeholder untuk kelancaran pelaksanaan tugas dan fungsi', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1, 2026, 'draft', '2026-04-27 17:15:06', 3, 'Pembina / IVa', 'Kepala Bagian Tata Usaha dan Umum', 'Bagian TU dan UMUM', 'Bagian TU dan UMUM'),
