(148, 'Sulastri Syarif, S.H.MM', '198211212005012001', 'Meydi Zulqadri, S.H.,M.H', '198705132010121006', '- Memahami dan memenuhi kebutuhan masyarakat.\n- Ramah, cekatan, solutif, dan dapat diandalkan.\n- Melakukan perbaikan tiada henti.', '- Melaksanakan tugas dengan jujur, bertanggungjawab, cermat, disiplin dan berintegritas tinggi.\n- Menggunakan kekayaan dan barang milik negara secara bertanggungjawab, efektif dan efisien.\n- Tidak menyalahgunakan kewenangan jabatan.', '- Meningkatkan kompetensi diri untuk menjawab tantangan yang selalu berubah.\n- Membantu orang lain belajar.\n- Melaksanakan tugas dengan kualitas terbaik.', '- Menghargai setiap orang apapun latar belakangnya.\n- Suka menolong orang lain.\n- Membangun lingkungan kerja yang kondusif.', '- Memegang teguh ideologi Pancasila, Undang-Undang Dasar Negara Republik Indonesia Tahun 1945, setia pada Negara Kesatuan Republik Indonesia serta pemerintahan yang sah.\n- Menjaga nama baik ASN, Pimpinan, Instansi dan Negara.\n- Menjaga rahasia jabatan dan negara.', '- Cepat menyesuaikan diri menghadapi perubahan\n- Terus berinovasi dan mengembangkan kreativitas\n- Bertindak proaktif', '- Memberi kesempatan kepada berbagai pihak untuk berkontribusi.\n- Terbuka dalam bekerjasama untuk menghasilkan nilai tambah.\n- Menggerakan pemanfaatan berbagai sumber daya untuk tujuan bersama.', 'Memberikan pelayanan prima yang responsif, ramah, dan sesuai standar.', 'Pegawai diharapkan melaksanakan tugas secara jujur, disiplin, dan bertanggung jawab serta mampu mempertanggungjawabkan setiap hasil kerja sesuai ketentuan yang berlaku.', 'Pegawai diharapkan memiliki dan terus meningkatkan kompetensi yang relevan dengan jabatan, serta mampu menghasilkan kinerja yang berkualitas sesuai standar yang ditetapkan.', 'Menjaga hubungan kerja yang saling menghargai, inklusif, dan kondusif', 'Pegawai diharapkan menunjukkan loyalitas kepada organisasi dengan memegang teguh nilai-nilai dasar ASN, menjaga nama baik instansi, serta mendukung kebijakan pimpinan secara bertanggung jawab.', 'Pegawai diharapkan mampu beradaptasi dengan perubahan lingkungan kerja, kebijakan, dan teknologi, serta menunjukkan sikap terbuka terhadap pembaruan dan perbaikan berkelanjutan.', 'Membangun kerja sama yang efektif dan sinergis dalam pelaksanaan tugas.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1, 2026, 'DISETUJUI', '2026-05-01 18:11:10', 150, ' Penata Muda Tk. I / IIIb', 'Analis SDM Aparatur Pertama', 'Bagian TU dan UMUM', 'Bagian TU dan UMUM');
INSERT INTO `skp_perilaku_awal_tahun_pegawai` (`ID_SKP`, `NAMA`, `NIP`, `NAMA_ATASAN_LANGSUNG`, `NIP_ATASAN_LANGSUNG`, `PERILAKU_KERJA_BERORIENTASI_PELAYANAN`, `PERILAKU_KERJA_AKUNTABEL`, `PERILAKU_KERJA_KOMPETEN`, `PERILAKU_KERJA_HARMONIS`, `PERILAKU_KERJA_LOYAL`, `PERILAKU_KERJA_ADAPTIF`, `PERILAKU_KERJA_KOLABORATIF`, `EKSPEKTASI_PIMPINAN_BERORIENTASI_PELAYANAN`, `EKSPEKTASI_PIMPINAN_AKUNTABEL`, `EKSPEKTASI_PIMPINAN_KOMPETEN`, `EKSPEKTASI_PIMPINAN_HARMONIS`, `EKSPEKTASI_PIMPINAN_LOYAL`, `EKSPEKTASI_PIMPINAN_ADAPTIF`, `EKSPEKTASI_PIMPINAN_KOLABORATIF`, `UMPAN_BALIK_BERORIENTASI_PELAYANAN`, `UMPAN_BALIK_AKUNTABEL`, `UMPAN_BALIK_KOMPETEN`, `UMPAN_BALIK_HARMONIS`, `UMPAN_BALIK_LOYAL`, `UMPAN_BALIK_ADAPTIF`, `UMPAN_BALIK_KOLABORATIF`, `TRIWULAN`, `TAHUN`, `STATUS`, `TANGGAL_INPUT_SKP`, `ID_SKP_GLOBAL`, `PANGKAT_GOL_RUANG`, `JABATAN`, `UNIT_KERJA`, `SATUAN_KERJA`) VALUES
(150, 'Basir, S.H., M.H.', '197211111993031001', 'Andi Basmal, S.Sos., S.H, M.H', '197202151992031002', '- Memahami dan memenuhi kebutuhan masyarakat.\n- Ramah, cekatan, solutif, dan dapat diandalkan.\n- Melakukan perbaikan tiada henti.', '- Melaksanakan tugas dengan jujur, bertanggungjawab, cermat, disiplin dan berintegritas tinggi.\n- Menggunakan kekayaan dan barang milik negara secara bertanggungjawab, efektif dan efisien.\n- Tidak menyalahgunakan kewenangan jabatan.', '- Meningkatkan kompetensi diri untuk menjawab tantangan yang selalu berubah.\n- Membantu orang lain belajar.\n- Melaksanakan tugas dengan kualitas terbaik.', '- Menghargai setiap orang apapun latar belakangnya.\n- Suka menolong orang lain.\n- Membangun lingkungan kerja yang kondusif.', '- Memegang teguh ideologi Pancasila, Undang-Undang Dasar Negara Republik Indonesia Tahun 1945, setia pada Negara Kesatuan Republik Indonesia serta pemerintahan yang sah.\n- Menjaga nama baik ASN, Pimpinan, Instansi dan Negara.\n- Menjaga rahasia jabatan dan negara.', '- Cepat menyesuaikan diri menghadapi perubahan\n- Terus berinovasi dan mengembangkan kreativitas\n- Bertindak proaktif', '- Memberi kesempatan kepada berbagai pihak untuk berkontribusi.\n- Terbuka dalam bekerjasama untuk menghasilkan nilai tambah.\n- Menggerakan pemanfaatan berbagai sumber daya untuk tujuan bersama.', 'Ekspektasi Khusus\r\nPimpinan :\r\nMemberikan layanan\r\nyang cepat dan\r\nramah, Bersedia\r\nditegur dan\r\nmemperbaiki\r\nkesalahan yang\r\ndilakukan', 'Ekspektasi Khusus\r\nPimpinan :\r\nMelaksanakan tugas\r\ndengan jujur dan\r\nbertanggung jawab\r\nserta menjunjung\r\ntinggi integritas\r\npegawai', 'Ekspektasi Khusus\r\nPimpinan :\r\nMenyelesaikan setiap\r\npekerjaan sesuai\r\ndengan target dan\r\nstandar kualitas yang\r\nditetapkan', 'Ekspektasi Khusus\r\nPimpinan : Saling\r\nmembantu dengan\r\nrekan kerja di\r\nSubBagian\r\nKepegawaian,\r\nkhususnya pekerjaan\r\nyang perlu\r\ndiselesaikan tepat\r\nwaktu', 'Ekspektasi Khusus\r\nPimpinan : Utamakan\r\ntugas dan fungsi\r\nsebagai ASN diatas\r\nkepentingan\r\npribadi/golongan', 'Ekspektasi Khusus\r\nPimpinan : Bersedia\r\nmengikuti pembinaan\r\ndan pengembangan\r\nkompetensi', 'Ekspektasi Khusus\r\nPimpinan : bangun\r\nkerjasama yang baik\r\ndengan Instansi\r\nterkait untuk\r\nkelancaran\r\npelaksanaan Tugas\r\ndan Fungsi', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1, 2026, 'SUBMITTED', '2026-05-01 19:01:33', 151, 'Pembina Utama Muda / IVc', 'Analis SDM Aparatur Madya', 'Bagian TU dan UMUM', 'Bagian TU dan UMUM'),
(152, 'Andi Wildania, S.H., M.H.', '198104102006042002', 'Dr. Ramli, S.H., M.H.', '198001092000031001', '- Memahami dan memenuhi kebutuhan masyarakat.\n- Ramah, cekatan, solutif, dan dapat diandalkan.\n- Melakukan perbaikan tiada henti.', '- Melaksanakan tugas dengan jujur, bertanggungjawab, cermat, disiplin dan berintegritas tinggi.\n- Menggunakan kekayaan dan barang milik negara secara bertanggungjawab, efektif dan efisien.\n- Tidak menyalahgunakan kewenangan jabatan.', '- Meningkatkan kompetensi diri untuk menjawab tantangan yang selalu berubah.\n- Membantu orang lain belajar.\n- Melaksanakan tugas dengan kualitas terbaik.', '- Menghargai setiap orang apapun latar belakangnya.\n- Suka menolong orang lain.\n- Membangun lingkungan kerja yang kondusif.', '- Memegang teguh ideologi Pancasila, Undang-Undang Dasar Negara Republik Indonesia Tahun 1945, setia pada Negara Kesatuan Republik Indonesia serta pemerintahan yang sah.\n- Menjaga nama baik ASN, Pimpinan, Instansi dan Negara.\n- Menjaga rahasia jabatan dan negara.', '- Cepat menyesuaikan diri menghadapi perubahan\n- Terus berinovasi dan mengembangkan kreativitas\n- Bertindak proaktif', '- Memberi kesempatan kepada berbagai pihak untuk berkontribusi.\n- Terbuka dalam bekerjasama untuk menghasilkan nilai tambah.\n- Menggerakan pemanfaatan berbagai sumber daya untuk tujuan bersama.', 'Memberikan layanan yang responsif dan ramah dalam memberikan layanan internal maupun eksternal', 'Melaksanakan tugas dengan jujur dan bertanggung jawab, cermat, dan disiplin serta menjunjung tinggi tata Nilai PASTI', 'Menyelesaikan  setiap  pekerjaan  sesuai  dengan  target  dan mampu meningkatkan kompetensi diri sesuai dengan tuntutan perubahan', 'Saling menghargai dengan pegawai lain untuk membangun lingkungan kerja yang nyaman dan kondusif', 'Mengutamakan kepentingan negara diatas kepentingan pribadi dan/atau golongan serta senantiasa menjaga nama baik ASN dan Institusi', 'Melakukan inovasi serta mampu menyesuaikan diri dalam menghadapi setiap perubahan', 'Membangun kerjasama yang baik dengan pimpinan, teman kerja dan stakeholder untuk kelancaran pelaksanaan tugas dan fungsi', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1, 2026, 'DISETUJUI', '2026-05-01 21:39:21', 152, 'Penata Tk.I / IIId', 'Penata Kelola Pemerintahan', 'Divisi Pelayanan Hukum', 'Divisi Pelayanan Hukum'),
